fn process_parallel(items: Vec<WorkItem>) -> Vec<Result<Output>> {
    let (tx, rx) = mpsc::channel();
    let pool = ThreadPool::new(num_cpus::get());
    let count = items.len();
    for item in items {
        let tx = tx.clone();
        pool.execute(move || {
            let result = item.process();
            tx.send(result).unwrap();
        });
    }
    drop(tx);
    rx.iter().take(count).collect()
}

func fanOut(ctx context.Context, input <-chan Job, workers int) <-chan Result {
    out := make(chan Result)
    var wg sync.WaitGroup
    for i := 0; i < workers; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for job := range input {
                select {
                case <-ctx.Done():
                    return
                case out <- job.Execute():
                }
            }
        }()
    }
    go func() {
        wg.Wait()
        close(out)
    }()
    return out
}

