fn mean_pooling(token_embeddings: &Array2<f32>, attention_mask: &Array1<f32>) -> Array1<f32> {
    let mask_expanded = attention_mask.insert_axis(Axis(1));
    let masked = token_embeddings * &mask_expanded;
    let summed = masked.sum_axis(Axis(0));
    let mask_sum = attention_mask.sum().max(1e-9);
    summed / mask_sum
}

class RateLimiter:
    def __init__(self, max_requests: int, window_seconds: float):
        self.max_requests = max_requests
        self.window = window_seconds
        self.requests = defaultdict(list)

    def allow(self, client_id: str) -> bool:
        now = time.time()
        window_start = now - self.window
        self.requests[client_id] = [
            t for t in self.requests[client_id] if t > window_start
        ]
        if len(self.requests[client_id]) >= self.max_requests:
            return False
        self.requests[client_id].append(now)
        return True

func NewTokenBucket(rate float64, burst int) *TokenBucket {
    return &TokenBucket{
        tokens:    float64(burst),
        maxTokens: float64(burst),
        refillRate: rate,
        lastRefill: time.Now(),
    }
}

func (tb *TokenBucket) Allow() bool {
    tb.mu.Lock()
    defer tb.mu.Unlock()
    now := time.Now()
    elapsed := now.Sub(tb.lastRefill).Seconds()
    tb.tokens = math.Min(tb.maxTokens, tb.tokens+elapsed*tb.refillRate)
    tb.lastRefill = now
    if tb.tokens < 1 {
        return false
    }
    tb.tokens--
    return true
}

