def validate_email(email: str) -> bool:
    if not email or '@' not in email:
        return False
    local, domain = email.rsplit('@', 1)
    if not local or not domain or '.' not in domain:
        return False
    return len(email) <= 254

def partition_by_predicate(items, predicate):
    true_items = []
    false_items = []
    for item in items:
        if predicate(item):
            true_items.append(item)
        else:
            false_items.append(item)
    return true_items, false_items

fn validate_input(data: &FormData) -> Result<(), Vec<String>> {
    let mut errors = Vec::new();
    if data.name.is_empty() {
        errors.push("Name is required".to_string());
    }
    if data.email.is_empty() || !data.email.contains('@') {
        errors.push("Valid email is required".to_string());
    }
    if errors.is_empty() { Ok(()) } else { Err(errors) }
}

fn group_by_key<K, V>(items: Vec<V>, key_fn: impl Fn(&V) -> K) -> HashMap<K, Vec<V>>
where K: Eq + Hash
{
    let mut map: HashMap<K, Vec<V>> = HashMap::new();
    for item in items {
        map.entry(key_fn(&item)).or_default().push(item);
    }
    map
}

